void load_exhanzi(int start,int end)
{
    for (int codepoint = start; codepoint <= end; codepoint++)
    {
        unsigned char utf8[4]; // UTF-8 最多占用 4 字节
        int len = 0;
        if (codepoint <= 0x7F) {
            utf8[len++] = codepoint;
        } else if (codepoint <= 0x7FF) {
            utf8[len++] = 0xC0 | (codepoint >> 6);
            utf8[len++] = 0x80 | (codepoint & 0x3F);
        } else if (codepoint <= 0xFFFF) {
            utf8[len++] = 0xE0 | (codepoint >> 12);
            utf8[len++] = 0x80 | ((codepoint >> 6) & 0x3F);
            utf8[len++] = 0x80 | (codepoint & 0x3F);
        } else if (codepoint <= 0x10FFFF) {
            utf8[len++] = 0xF0 | (codepoint >> 18);
            utf8[len++] = 0x80 | ((codepoint >> 12) & 0x3F);
            utf8[len++] = 0x80 | ((codepoint >> 6) & 0x3F);
            utf8[len++] = 0x80 | (codepoint & 0x3F);
        }
        if (len==4)
        {
            hanzi_len_4++;
            for (int i = 0; i < len; i++) hanzi_4[++hanzi_cnt_4]=utf8[i];
        }
        if (len==3)
        {
            hanzi_len_3++;
            for (int i = 0; i < len; i++) hanzi_3[++hanzi_cnt_3]=utf8[i];
        }
    }
}
