	void calc_skills(const char *name)
	{
		q_len=-1;
		for (int i = 0; i < N; i += 8) {
			ual[i + 0] = val[i + 0] * 181 + 71;
			ual[i + 1] = val[i + 1] * 181 + 71;
			ual[i + 2] = val[i + 2] * 181 + 71;
			ual[i + 3] = val[i + 3] * 181 + 71;
			ual[i + 4] = val[i + 4] * 181 + 71;
			ual[i + 5] = val[i + 5] * 181 + 71;
			ual[i + 6] = val[i + 6] * 181 + 71;
			ual[i + 7] = val[i + 7] * 181 + 71;
		}
		
		for (int i = 0; i < N; i ++)
			if ((ual[i] & 0x80) == 0)
				name_base[++q_len] = (ual[i]+89) & 63;

		u8_t *a = name_base + K;
		for (int i = 0; i < skill_cnt; i ++) skill[i] = i;
		memset(freq, 0, sizeof freq);
		p = q = 0;
		for (int s = 0, _ = 0; _ < 2; _ ++)
			for (int i = 0; i < skill_cnt; i ++) {
				s = (s + gen() + skill[i]) % skill_cnt;
				swap(skill[i], skill[s]);
			}
		int last = -1;
		for (int i = 0, j = 0; i < K; i += 4, j ++) {
			u8_t p = min({a[i], a[i + 1], a[i + 2], a[i + 3]});
			if (p > 10 && skill[j] < 35) {
				freq[j] = p - 10;
				if (skill[j] < 25) last = j;
			}
			else freq[j] = 0;
		}
		if (last != -1) freq[last] <<= 1;
		if (freq[14] && last != 14)
			freq[14] += min({name_base[60], name_base[61], freq[14]});
		if (freq[15] && last != 15)
			freq[15] += min({name_base[62], name_base[63], freq[15]});
	}
