void hanxu_Poly(double *xp,double *x) {
	int l,i,p,q,j;
	double r;
    for (int y = 0; y < 1034; y++) {
        l = 44;
        i = 0, p = 0, q = 0;
		r = 0;
        j = y;
        for (int k = 0; k < 45; k++) {
            i++, p += (i>2), q = j, j = j - l + p;
            if (j < 0) break;
        }
        if (i == 1) r = x[q];
        if (i > 1) r = x[p] * x[p + q];
        xp[y] = r;
    }
}
