void get_fname_2()
{
	read(fname);
	fprintf(stderr,"fname=%s\n",fname);
	for (int i=100;i>=6;i--) fname[i]=fname[i-6];
	fname[0]='.';fname[1]='/';fname[2]='o';fname[3]='u';fname[4]='t';fname[5]='/';
}
void get_fname_1()
{
	read(fname);
	if (fname[0]=='+'&&fname[1]=='\0')
	{
		fname[0]='o',fname[1]='u',fname[2]='t',fname[3]='-';
		for (int i=4;i<=10;i++) fname[i]=Rnd()%10+'0';
		fname[11]='.',fname[12]='t',fname[13]='x',fname[14]='t';
		fname[15]='\0';
	} else 	if (fname[0]=='-'&&fname[1]=='\0') getfilename();
	fprintf(stderr,"fname=%s\n",fname);
	for (int i=100;i>=6;i--) fname[i]=fname[i-6];
	fname[0]='.';fname[1]='/';fname[2]='o';fname[3]='u';fname[4]='t';fname[5]='/';
}

void read_fix(char *x,int & len)
{
	memset(_tmp,0,sizeof(_tmp));for (int i=0;i<N;i++) x[i]=0;
	read(_tmp);
	
	for (int i=0;i<64;i++) x[i]=_tmp[i];
	len = jyztxdy = strlen(x);
	if (x[0] == '+' || x[0]=='@') len = 0;
	for (int i=len+1;i<N;i++) x[i]=0;
	if (x[0] == '@') 
	{
		puts_Chinese("输入转化编码后的长度");
		cin>>len;int xx;
		puts_Chinese("输入转化编码后的每个数字");
		for (int i=0;i<len;i++)cin>>xx,x[i]=xx;
		char ccc=getchar();while (ccc!='\n') ccc=getchar();
	}
}
