int main()
{
    system("chcp 65001 >nul");
	freopen("input_daily.txt","r",stdin);
    init_exhanzi();
	choose_mode();
	choose_settings();
	
    pthread_create(&ptid,NULL,producer,NULL);
    for (int i=0;i<NUMBER_OF_WORKER_THREAD;i++) pthread_create(&ctid[i],NULL,consumer,NULL);
	if (DEBUG_MOD_ON<2) pthread_create(&rtid,NULL,reader,NULL);
    pthread_join(ptid,NULL);
    for (int i=0;i<NUMBER_OF_WORKER_THREAD;i++) pthread_join(ctid[i],NULL);
	if (DEBUG_MOD_ON<2) pthread_join(rtid,NULL);
	fputs("Done.Click enter to close.", stderr);

	system("pause");	
}